// GamesByRoundCodesDS is the DS-only mirror of GamesByRoundCodes: it
// strips any GA-prefixed code from the caller's slice before delegating
// to GamesByRoundCodes, so no GA round can ever bleed back through.
// Returns (nil, nil) when the filtered slice is empty (matches the
// behaviour of GamesByRoundCodes on an empty input).
func GamesByRoundCodesDS(codes []string) ([]*models.GameRound, error) {
	if len(codes) == 0 {
		return nil, nil
	}
	filtered := make([]string, 0, len(codes))
	for _, c := range codes {
		if !strings.HasPrefix(c, "GA") {
			filtered = append(filtered, c)
		}
	}
	if len(filtered) == 0 {
		return nil, nil
	}
	return GamesByRoundCodes(filtered)
}

// GameByRoundCodeDS is the DS-only mirror of GameByRoundCode: returns
// (nil, nil) for GA-prefixed codes without touching the DB. Callers on
// the DS path treat "no DS round for this code" as a legitimate absence
// rather than an error, so we surface no error here either.
func GameByRoundCodeDS(roundCode string) (*models.GameRound, error) {
	if strings.HasPrefix(roundCode, "GA") {
		return nil, nil
	}
	return GameByRoundCode(roundCode)
}

// GamesAfterGameIDDS is the DS-only mirror of GamesAfterGameID. The
// pivot (`gameID`) is looked up unfiltered — callers on the DS path only
// pass DS codes by construction — but the returned window has
// `RoundCode NOT LIKE 'GA%'` so GA rounds inserted between the pivot
// and "now" can never sneak into the DS path's resync slice.
func GamesAfterGameIDDS(betofferID int, gameID string, limit int) ([]*models.GameRound, error) {
	var pivotStartDt string
	if err := db.QueryRow(
		`SELECT VideoStartDt FROM GameRounds WHERE RoundCode=?`,
		gameID,
	).Scan(&pivotStartDt); err != nil {
		return nil, fmt.Errorf("pivot lookup DS for %s: %w", gameID, err)
	}
	q := `SELECT ` + gameRoundSelectCols + `
		FROM GameRounds
		WHERE GameTypeId=? AND VideoStartDt > ? AND RoundCode NOT LIKE 'GA%'
		ORDER BY VideoStartDt ASC
		LIMIT ?`
	rows, err := db.Query(q, betofferID, pivotStartDt, limit)
	if err != nil {
		return nil, fmt.Errorf("query after DS: %w", err)
	}
	defer rows.Close()
	return scanGameRounds(rows)
}

// StatsHistoryDS is the DS-only mirror of StatsHistory: history rows
// (each = the finish positions of a round), newest/oldest RoundCode of
// the window. Same shape and semantics as StatsHistory, but restricted
// to DS rounds. Returns ([][]int{}, "", "", nil) when the betoffer has
// no finished DS rounds (matches StatsHistory's empty-window contract).
func StatsHistoryDS(betofferID, limit int) (history [][]int, newest, oldest string, err error) {
	q := `SELECT RoundCode FROM GameRounds
		WHERE GameTypeId=? AND Status='F' AND RoundCode NOT LIKE 'GA%'
		ORDER BY VideoStartDt DESC LIMIT ?`
	rows, err := db.Query(q, betofferID, limit)
	if err != nil {
		return nil, "", "", fmt.Errorf("query stats DS: %w", err)
	}
	defer rows.Close()
	var codes []string
	for rows.Next() {
		var c string
		if err := rows.Scan(&c); err != nil {
			return nil, "", "", fmt.Errorf("scan stats DS: %w", err)
		}
		codes = append(codes, c)
	}
	if err := rows.Err(); err != nil {
		return nil, "", "", err
	}
	if len(codes) == 0 {
		return [][]int{}, "", "", nil
	}
	newest = codes[0]
	oldest = codes[len(codes)-1]

	resultMap, err := ResultsBatch(codes)
	if err != nil {
		return nil, "", "", fmt.Errorf("results for stats DS: %w", err)
	}
	history = make([][]int, 0, len(codes))
	for _, c := range codes {
		results := resultMap[c]
		positions := make([]int, len(results))
		for _, r := range results {
			if r.Position >= 1 && r.Position <= len(positions) {
				positions[r.Position-1] = r.RunnerNumber
			}
		}
		history = append(history, positions)
	}
	return history, newest, oldest, nil
}

// ResultsByRoundCodeDS is the DS-only mirror of ResultsByRoundCode:
// caller-side prefix check, returns (nil, nil) for GA codes without
// hitting the DB.
func ResultsByRoundCodeDS(roundCode string) ([]models.GameResult, error) {
	if strings.HasPrefix(roundCode, "GA") {
		return nil, nil
	}
	return ResultsByRoundCode(roundCode)
}

// GamesByRoundCodesGA is the GA-only mirror of GamesByRoundCodesDS: it
// keeps only GA-prefixed codes before delegating to GamesByRoundCodes,
// so a DS round can never bleed into the GA (race-broadcaster) path.
// Returns (nil, nil) when the filtered slice is empty.
func GamesByRoundCodesGA(codes []string) ([]*models.GameRound, error) {
	if len(codes) == 0 {
		return nil, nil
	}
	filtered := make([]string, 0, len(codes))
	for _, c := range codes {
		if strings.HasPrefix(c, "GA") {
			filtered = append(filtered, c)
		}
	}
	if len(filtered) == 0 {
		return nil, nil
	}
	return GamesByRoundCodes(filtered)
}

// GameByRoundCodeGA is the GA-only mirror of GameByRoundCodeDS: returns
// (nil, nil) for non-GA codes without touching the DB. Callers on the
// GA path treat "no GA round for this code" as a legitimate absence.
func GameByRoundCodeGA(roundCode string) (*models.GameRound, error) {
	if !strings.HasPrefix(roundCode, "GA") {
		return nil, nil
	}
	return GameByRoundCode(roundCode)
}

// ResultsByRoundCodeGA is the GA-only mirror of ResultsByRoundCodeDS:
// caller-side prefix check, returns (nil, nil) for non-GA codes without
// hitting the DB.
func ResultsByRoundCodeGA(roundCode string) ([]models.GameResult, error) {
	if !strings.HasPrefix(roundCode, "GA") {
		return nil, nil
	}
	return ResultsByRoundCode(roundCode)
}
